]!), subtitle: Text("Tarih: " + sktList[i]["tarih"]!))))])); } void _addSKT() { showDialog(context: context, builder: (c) => AlertDialog(title: Text("Urun Ekle"), content: Column(mainAxisSize: MainAxisSize.min, children: [TextField(onSubmitted: (v) { setState(() => sktList.add({"ad": v, "tarih": "Kaydedildi"})); Navigator.pop(c); }, decoration: InputDecoration(hintText: "Urun Adi (Orn: Sut)"))]))); } Widget _cat(IconData i, String t) => Padding(padding: EdgeInsets.all(10), child: Column(children: [CircleAvatar(backgroundColor: Colors.orange.shade50, child: Icon(i, color: Colors.orange)), Text(t, style: TextStyle(fontSize: 12))])); Widget _gameCard(IconData i, String t, Function() f) => InkWell(onTap: f, child: Card(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [Icon(i, size: 40, color: Colors.orange), Text(t)]))); } class GuessGame extends StatefulWidget { @override _GuessGameState createState() => _GuessGameState(); } class _GuessGameState extends State<GuessGame> { int target = Random().nextInt(100); int count = 0; String msg = "1-100 arasi bir sayi tuttum!"; void check(int v) { setState(() { count++; if (v < target) msg = "Daha BUYUK!"; else if (v > target) msg = "Daha KUCUK!"; else msg = "TEBRIKLER! $count. denemede buldun!"; }); } @override Widget build(BuildContext context) { return Scaffold(appBar: AppBar(title: Text("Sayi Tahmin")), body: Column(mainAxisAlignment: MainAxisAlignment.center, children: [Text(msg, style: TextStyle(fontSize: 20)), Padding(padding: EdgeInsets.all(40), child: TextField(keyboardType: TextInputType.number, onSubmitted: (v) => check(int.parse(v)), decoration: InputDecoration(hintText: "Sayiyi Yaz ve Enter de"))), ElevatedButton(onPressed: () => setState(() { target = Random().nextInt(100); count = 0; msg = "Yeni sayi tutuldu!"; }), child: Text("Yeniden Basla"))])); } }
